 * Calculates the sum of absolute differences in frequencies between characters and their mirrored characters.
 * @param {string} s The input string composed of lowercase letters and digits.
 * @returns {number} The total sum of absolute differences.
 */
function solve(s) {
    // Step 1: Frequency Counting
    const freq = new Map();
    for (const char of s) {
        freq.set(char, (freq.get(char) || 0) + 1);
    }

    /**
     * Calculates the mirrored character for a given input character.
     * @param {string} c The character.
     * @returns {string} The mirrored character.
     */
    const getMirror = (c) => {
        const charCode = c.charCodeAt(0);

        // Check for lowercase letters (a-z)
        if (charCode >= 'a'.charCodeAt(0) && charCode <= 'z'.charCodeAt(0)) {
            const offset = charCode - 'a'.charCodeAt(0);
            // Mirror index: 25 - offset
            const mirroredOffset = 25 - offset;
            return String.fromCharCode('a'.charCodeAt(0) + mirroredOffset);
        }

        // Check for digits (0-9)
        if (charCode >= '0'.charCodeAt(0) && charCode <= '9'.charCodeAt(0)) {
            const digit = parseInt(c);
            // Mirror digit: 9 - digit
            const mirroredDigit = 9 - digit;
            return String(mirroredDigit);
        }

        // Should not happen based on constraints
        return null;
    };

    let totalDifference = 0;
    const processedPairs = new Set();
    const uniqueChars = Array.from(freq.keys());

    // Step 3: Iterate and Sum
    for (const c of uniqueChars) {
        const m = getMirror(c);

        // Canonical representation of the pair {c, m}
        const pairKey = c < m ? `${c},${m}` : `${m},${c}`;

        if (processedPairs.has(pairKey)) {
            continue;
        }

        processedPairs.add(pairKey);

        const freqC = freq.get(c);
        // freqM is 0 if the mirror character m is not in the string s
        const freqM = freq.get(m) || 0;

        const difference = Math.abs(freqC - freqM);
        totalDifference += difference;
    }

    return totalDifference;
